import java.util.HashMap;
import java.util.Map;
import javax.naming.Context;
import javax.naming.NamingEnumeration;
import javax.naming.NamingException;
import javax.naming.directory.Attribute;
import javax.naming.directory.Attributes;
import javax.naming.directory.DirContext;
import javax.naming.directory.InitialDirContext;
import javax.naming.directory.SearchControls;
import javax.naming.directory.SearchResult;

public class LdapUserSearch {
    private static final String PROVIDER_URL = "ldap://localhost:10389";
    private static final String BASE_DN = "dc=example,dc=com";
    private static final String USERNAME_ATTRIBUTE = "uid";
    private static final String EMAIL_ATTRIBUTE = "mail";
    private static final String FULL_NAME_ATTRIBUTE = "cn";
    private static final String DEPARTMENT_ATTRIBUTE = "departmentNumber";

    public Map<String, Object> searchUser(String username) throws NamingException {
        // Create an initial context
        DirContext ctx = new InitialDirContext();

        // Define the search controls
        SearchControls controls = new SearchControls();
        controls.setSearchScope(SearchControls.SUBTREE_SCOPE);
        controls.setReturningAttributes(new String[] { USERNAME_ATTRIBUTE, EMAIL_ATTRIBUTE, FULL_NAME_ATTRIBUTE, DEPARTMENT_ATTRIBUTE });

        // Perform the search
        NamingEnumeration<SearchResult> results = ctx.search(BASE_DN, "(&(" + USERNAME_ATTRIBUTE + "=" + username + "))", controls);

        // Check if a result was found
        if (!results.hasMore()) {
            return null;
        }

        // Get the search result
        SearchResult result = results.next();

        // Create a map to store the user attributes
        Map<String, Object> userAttributes = new HashMap<>();

        // Add the user attributes to the map
        Attributes attrs = result.getAttributes();
        for (Attribute attr : attrs.getAll()) {
            String attributeName = attr.getID().toLowerCase();
            if (attributeName.equals(USERNAME_ATTRIBUTE)) {
                userAttributes.put("username", attr.get());
            } else if (attributeName.equals(EMAIL_ATTRIBUTE)) {
                userAttributes.put("email", attr.get());
            } else if (attributeName.equals(FULL_NAME_ATTRIBUTE)) {
                userAttributes.put("fullName", attr.get());
            } else if (attributeName.equals(DEPARTMENT_ATTRIBUTE)) {
                userAttributes.put("department", attr.get());
            }
        }

        // Return the map of user attributes
        return userAttributes;
    }
}